class Solution:
    def maxIncreasingGroups(self, usageLimits: List[int]) -> int:
        usageLimits.sort()
        res = 0
        total = 0
        for limit in usageLimits:
            total += limit
            res += 1
            if total < res * (res + 1) // 2:
                res -= 1
        return res
